import React, { useState, useEffect } from 'react';
import './MoviePlayer.css';

const MoviePlayer = ({ movie, onClose }) => {
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    if (movie) {
      setIsOpen(true);
      document.body.style.overflow = 'hidden';
    }
  }, [movie]);

  const handleClose = () => {
    setIsOpen(false);
    document.body.style.overflow = 'auto';
    if (onClose) onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="player-overlay" onClick={handleClose}>
      <div className="player-container" onClick={(e) => e.stopPropagation()}>
        <div className="video-placeholder">
          <div className="fake-player" id="fakePlayer" style={{ display: movie?.video_url ? 'none' : 'flex' }}>
            <div className="play-icon">▶</div>
            <div className="player-meta">{movie?.title || 'Выберите фильм'}</div>
            <div className="player-subtitle">✧ нажмите для просмотра ✧</div>
          </div>
          {movie?.video_url && (
            <iframe
              id="realPlayer"
              className="real-player"
              src={movie.video_url}
              allow="autoplay; fullscreen; picture-in-picture"
              allowFullScreen
              title={movie.title}
            />
          )}
        </div>
      </div>
      <button className="close-player" onClick={handleClose}>
        ЗАКРЫТЬ ПЛЕЕР [X]
      </button>
    </div>
  );
};

export default MoviePlayer;
